import React from 'react';
import { Routes, Route } from 'react-router-dom';
import Header from './components/Header';
const Home = () => <h2>Home Page</h2>;


function App() {
  return (
    <div>
      <h1>Welcome to Plant Nursery App</h1>
      <Header />
      <Routes>
        <Route path="/" element={<Home />} />
      </Routes>
    </div>
  );
}

export default App;
